{
  "name": "HUSKY Health (Medicaid for seniors/disabled)",
  "eligibility": {
    "age": 65,
    "income_limits": "Varies by subcategory. Standard HUSKY C: Single - $851/month, Couple - $1,153/month (excludes unearned income disregard). Long-Term Services & Supports (LTSS): Single - $2,982/month; married couple based on CSPA. MED-Connect (working disabled): Up to $85,000/year. Note: 2026 updates may adjust to ~$1,413/month single for regular ABD per some sources, effective 3/1/26.[1][2][5]",
    "asset_limits": "Standard HUSKY C: Single - $1,600, Couple - $2,400. LTSS: Single - $1,600, Couple - based on CSPA. MED-Connect: Single - $20,000, Couple - $30,000. Countable assets include cash, stocks, bonds, investments, IRAs, bank accounts, non-primary real estate. Exemptions not fully detailed but typically include primary home (under equity limits), one vehicle, personal belongings.[1][2][3][5]",
    "other_requirements": ["Connecticut resident", "Blind, disabled, or 65+", "For LTSS: Nursing home level of care or help with ADLs required", "For MED-Connect: Employed with disability", "U.S. citizen or qualified non-citizen"]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive Medicaid health coverage including doctor visits, hospital care, prescription drugs, dental, vision, mental health; long-term services & supports (LTSS) for home/community-based services, nursing homes, assisted living, adult foster care; non-medical supports to remain at home. Specifics: covers variety of health care services per benefit overview.[2][4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: portal.ct.gov/HUSKY or www.accesshealthct.com", "Phone: Connecticut Health Care Referrals at 1-877-284-4911 (inquiries/enrollment)", "Mail or in-person: Department of Social Services (DSS) offices; apply via Access Health CT or DSS", "MED-Connect/LTSS: Specific referral links at portal.ct.gov/HUSKY/How-to-Qualify or www.ct.gov/med"],
    "processing_time": "Not specified in sources",
    "waitlist": "Entitlement program (no waitlist if eligible)",
    "forms": ["Complete application via Access Health CT or DSS (no specific form number listed)"],
    "documents": ["Proof of income, assets, residency, age/disability (SSDI award letter, bank statements, pay stubs, property deeds), citizenship/immigration status, for LTSS: 5-year income/asset review if new to DSS Medicaid"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Connecticut residents only",
    "regional_variations": null,
    "offices_or_providers": ["Department of Social Services (DSS) statewide; local DSS offices for in-person"]
  },
  "official_source": "https://portal.ct.gov/HUSKY/How-to-Qualify",
  "gotchas": ["Multiple subprograms (standard HUSKY C, LTSS, MED-Connect) with different income/asset limits—must identify correct category", "Asset test applies (unlike HUSKY A/D)", "LTSS requires level of care determination and potential 5-year lookback", "Working disabled may owe premium under MED-Connect", "Income limits updated annually (e.g., March); 2026 changes pending", "CSPA protections for community spouse in married LTSS cases"],
  "data_shape_notes": "Tiered by subcategory (standard ABD, LTSS, MED-Connect) with varying income/asset limits; asset test required; LTSS needs care level assessment; statewide but subcategory-specific referrals"
}

{
  "name": "CHOICES (CT SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; free and unbiased services available to all Medicare-eligible individuals, families, and caregivers of all ages and income levels[2][5][6].",
    "asset_limits": "No asset limits or tests apply[6].",
    "other_requirements": [
      "Medicare-eligible: US citizens or permanent residents aged 65+; certain younger people with disabilities approved by Social Security Administration (e.g., collecting SSDI for 24 months); or those who worked 40 quarters eligible for Social Security/Railroad Retirement[3][5][9]",
      "Connecticut residents[1][2][5]",
      "Includes caregivers, providers, and those becoming eligible for Medicare; no prior Medicare experience required[1][9]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one benefits counseling on Medicare Parts A/B (Original), C (Advantage), Supplement, D (Prescription Drugs); enrollment assistance and plan comparisons for Part C/D; eligibility screening and application assistance for cost-assistance programs (Medicaid, Medicare Savings Program, Low-Income Subsidy/Extra Help); outreach, information/referral, claims dispute guidance; long-term care info[2][5][7][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: Call 800.994.9422 or local SHIP/CHOICES counselor[5][7]",
      "In-person: Accessible locations throughout the state via 5 Area Agencies on Aging (AAAs) or community organizations[2][5][7]",
      "Contact local AAA or Center for Medicare Advocacy partners for counseling sessions[2][8]"
    ],
    "processing_time": "No formal application processing; counseling provided upon contact, though training/certification for counselors may influence availability[6]",
    "waitlist": null,
    "forms": [
      "IEP (Initial Enrollment Period form) may be used for Part C/D enrollment[3]"
    ],
    "documents": [
      "No specific documents required for counseling; for eligibility screening/application assistance: Medicare card, income proof, SSDI/SS award letters if applicable[3][7]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Connecticut residents only[1][2][5]",
    "regional_variations": "Administered regionally by 5 Area Agencies on Aging (AAAs) with local providers and accessible locations; services consistent statewide but delivered through regional AAAs and partners like Center for Medicare Advocacy[2][5][8]",
    "offices_or_providers": [
      "5 Area Agencies on Aging (AAAs)",
      "Center for Medicare Advocacy, Inc.",
      "Local examples: Western CT AoA (203.785.8533), Senior Resources EC, Windham CT[2][3][7]"
    ]
  },
  "official_source": "https://portal.ct.gov/ads/programs-and-services/choices[5]",
  "gotchas": [
    "Not a direct service/financial benefit program—provides counseling and assistance only, not healthcare or payments[2][5]",
    "Counselors are trained volunteers/staff, not insurance agents; no financial gain from recommendations[2][6]",
    "Confused with Medicare itself or other CT programs; it's SHIP for navigation help[1][4]",
    "Open Enrollment (Oct 15-Dec 7) critical period—contact for timely help[8]",
    "Employer group health plans or HSAs may affect Medicare enrollment timing[3]"
  ],
  "data_shape_notes": "No income/asset tests; volunteer/staff-delivered counseling via 5 regional AAAs; partners with Center for Medicare Advocacy; open to all Medicare-eligible CT residents and caregivers"
}

{
  "name": "Long Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all regardless of financial status.",
    "asset_limits": "No asset limits or tests; no assets count or are exempt as there is no financial eligibility.",
    "other_requirements": ["Residency in a Connecticut skilled nursing facility, residential care home, assisted living/managed residential services facility, or board and care home.", "Open to residents, their family members or friends, facility staff with resident concerns, individuals considering placement, or citizen groups interested in resident welfare."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including resolving complaints confidentially (with permission to share), providing information on facilities and quality care, promoting resident rights, facilitating communication between residents/families and staff, supporting family/resident councils, and visiting facilities to address issues like diet changes, timely assistance, or activities.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 860-424-5200 or 1-866-388-1888.", "Email: LTCOP@CT.GOV.", "In-person or mail: 55 Farmington Avenue, Hartford, CT 06105-3730.", "Website: https://portal.ct.gov/LTCOP (for information and contacts)."],
    "processing_time": "Immediate assistance available upon contact; no formal processing as it's an advocacy hotline/service.",
    "waitlist": null,
    "forms": ["No specific application forms for receiving services; for volunteering: Volunteer Resident Advocate Application, Verification Form, Reference Form, Conflict of Interest Screening Form."],
    "documents": ["No documents required to receive services; contact directly with concerns."]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Regional Ombudsmen serve different areas of Connecticut, but core services are uniform statewide with central coordination from Hartford office.",
    "offices_or_providers": ["Central office: 55 Farmington Avenue, Hartford, CT 06105-3730.", "Regional Ombudsman programs (search Community Resources Database for local providers)."]
  },
  "official_source": "https://portal.ct.gov/LTCOP",
  "gotchas": ["Services are free advocacy, not financial aid, healthcare, or housing placement—focuses on rights protection and complaint resolution in long-term care facilities.", "Confidentiality maintained unless permission given to act on complaints.", "Not for general elderly care outside licensed long-term care facilities.", "Volunteering has restrictions (e.g., cannot if employed by or owning a facility, or if immediate family resides there).", "Families considering placement can get info, but must be for covered facility types."],
  "data_shape_notes": "no income test; advocacy-only with no financial eligibility, asset review, waitlists, or tiered benefits; open to residents/families pre- and post-placement in specific facility types; volunteer-driven with regional staff support."
}
